import{_ as e,o as d,c as a,ag as o}from"./chunks/framework.C9sp7nFj.js";const b=JSON.parse('{"title":"斜杠命令","description":"","frontmatter":{},"headers":[],"relativePath":"zh/getting-started/slash-commands.md","filePath":"zh/getting-started/slash-commands.md","lastUpdated":1778142998000}'),c={name:"zh/getting-started/slash-commands.md"};function s(r,t,n,l,h,i){return d(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="斜杠命令" tabindex="-1">斜杠命令 <a class="header-anchor" href="#斜杠命令" aria-label="Permalink to &quot;斜杠命令&quot;">​</a></h1><p>Memoh 支持 <strong>斜杠命令</strong>，在进 LLM 之前截获。用来快速看状态、改配置、切模型、开会话、停生成等。外接渠道和内置网页聊天都支持；<strong>解析命令本身一般不吃模型 token</strong>（与真正进对话的内容无关）。</p><hr><h2 id="命令长什么样" tabindex="-1">命令长什么样 <a class="header-anchor" href="#命令长什么样" aria-label="Permalink to &quot;命令长什么样&quot;">​</a></h2><p>多数命令是「资源 / 动作 / 参数」：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/resource [action] [arguments...]</span></span></code></pre></div><p>例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/schedule list</span></span>\n<span class="line"><span>/model current</span></span>\n<span class="line"><span>/schedule create morning-news &quot;0 9 * * *&quot; &quot;Send a daily summary&quot;</span></span></code></pre></div><p>要点：</p><ul><li><strong>resource</strong> 是组，如 <code>schedule</code>、<code>model</code>、<code>status</code>。</li><li><strong>action</strong> 是具体子命令，如 <code>list</code>、<code>get</code>、<code>set</code>。</li><li><strong>arguments</strong> 在 action 后面；带空格的用引号包起来。</li><li>有的组有<strong>默认动作</strong>，例如 <code>/settings</code> 等于 <code>/settings get</code>，<code>/status</code> 等于 <code>/status show</code>。</li></ul><p>另有两条<strong>顶层</strong>命令：</p><ul><li><code>/new</code>：给当前会话路由新开一路会话</li><li><code>/stop</code>：停当前这一路正在生成</li></ul><hr><h2 id="内建帮助" tabindex="-1">内建帮助 <a class="header-anchor" href="#内建帮助" aria-label="Permalink to &quot;内建帮助&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>作用</th></tr></thead><tbody><tr><td><code>/help</code></td><td>顶层命令列表</td></tr><tr><td><code>/help &lt;group&gt;</code></td><td>某组里有哪些 action</td></tr><tr><td><code>/help &lt;group&gt; &lt;action&gt;</code></td><td>某条 action 的用法</td></tr></tbody></table><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/help</span></span>\n<span class="line"><span>/help model</span></span>\n<span class="line"><span>/help model set</span></span></code></pre></div><p>这是查<strong>当前版本</strong>实际支持哪些命令最快的方式。</p><hr><h2 id="解析规则" tabindex="-1">解析规则 <a class="header-anchor" href="#解析规则" aria-label="Permalink to &quot;解析规则&quot;">​</a></h2><ul><li>群里可 <strong>@机器人 前缀</strong>，如 <code>@BotName /help</code>。</li><li><strong>Telegram</strong> 可带 bot 后缀，如 <code>/help@MemohBot</code>。</li><li>引号包一整个参数，例如：</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/schedule create morning-news &quot;0 9 * * *&quot; &quot;Send today&#39;s top stories&quot;</span></span></code></pre></div><p>整行<strong>对不上</strong>已知命令时，当普通聊天发出去，不当斜杠命令。</p><hr><h2 id="权限" tabindex="-1">权限 <a class="header-anchor" href="#权限" aria-label="Permalink to &quot;权限&quot;">​</a></h2><p>只读类：能跟机器人聊的人一般就能用。<br><code>set</code>、<code>create</code>、<code>update</code>、<code>delete</code>、<code>enable</code>、<code>disable</code> 等写操作多要 <strong>owner</strong>。</p><p><code>/help</code> 里 owner 专属会标 <code>[owner]</code>。</p><hr><h2 id="速查" tabindex="-1">速查 <a class="header-anchor" href="#速查" aria-label="Permalink to &quot;速查&quot;">​</a></h2><h3 id="顶层" tabindex="-1">顶层 <a class="header-anchor" href="#顶层" aria-label="Permalink to &quot;顶层&quot;">​</a></h3><table tabindex="0"><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td><code>/help</code></td><td>帮助</td></tr><tr><td><code>/new</code>（可选 <code>chat</code> / <code>discuss</code>）</td><td>新会话</td></tr><tr><td><code>/stop</code></td><td>停当前生成</td></tr></tbody></table><h3 id="资源组" tabindex="-1">资源组 <a class="header-anchor" href="#资源组" aria-label="Permalink to &quot;资源组&quot;">​</a></h3><table tabindex="0"><thead><tr><th>组</th><th>说明</th><th>默认动作</th></tr></thead><tbody><tr><td><code>/schedule</code></td><td>计划任务</td><td>无</td></tr><tr><td><code>/mcp</code></td><td>看 MCP 连接</td><td>无</td></tr><tr><td><code>/settings</code></td><td>机器人设置</td><td><code>get</code></td></tr><tr><td><code>/model</code></td><td>聊天/心跳模型</td><td>无</td></tr><tr><td><code>/memory</code></td><td>记忆提供方</td><td>无</td></tr><tr><td><code>/search</code></td><td>搜索提供方</td><td>无</td></tr><tr><td><code>/usage</code></td><td>token 用量</td><td><code>summary</code></td></tr><tr><td><code>/email</code></td><td>邮服、绑定、发件箱</td><td>无</td></tr><tr><td><code>/heartbeat</code></td><td>心跳日志</td><td><code>logs</code></td></tr><tr><td><code>/skill</code></td><td>技能列表</td><td><code>list</code></td></tr><tr><td><code>/fs</code></td><td>容器内文件</td><td>无</td></tr><tr><td><code>/status</code></td><td>会话消息/上下文/缓存</td><td><code>show</code></td></tr><tr><td><code>/access</code></td><td>身份与 ACL</td><td><code>show</code></td></tr><tr><td><code>/compact</code></td><td>立刻做<strong>会话</strong>上下文压缩</td><td><code>run</code></td></tr></tbody></table><hr><h2 id="会话类" tabindex="-1">会话类 <a class="header-anchor" href="#会话类" aria-label="Permalink to &quot;会话类&quot;">​</a></h2><h3 id="new" tabindex="-1"><code>/new</code> <a class="header-anchor" href="#new" aria-label="Permalink to &quot;`/new`&quot;">​</a></h3><p>给<strong>当前会话路由</strong>新开会话，老历史还在，只是切到新的当前上下文。</p><ul><li><code>/new</code>：按当前场景默认类型</li><li><code>/new chat</code>：强制 chat</li><li><code>/new discuss</code>：强制 discuss</li></ul><p>默认：网页本地多 <code>chat</code>；私聊多 <code>chat</code>；外接群多 <code>discuss</code>。</p><p><strong>内置网页本地</strong> 没有 <code>/new discuss</code>，要 discuss 请用 Telegram、Discord 等。</p><p>细节见 <a href="/zh/getting-started/sessions.html">会话</a>。</p><h3 id="stop" tabindex="-1"><code>/stop</code> <a class="header-anchor" href="#stop" aria-label="Permalink to &quot;`/stop`&quot;">​</a></h3><p>停<strong>当前这一路</strong>正在生成。适合：流式已经够了、工具转太久、要在下一句前打断。</p><hr><h2 id="状态与排查" tabindex="-1">状态与排查 <a class="header-anchor" href="#状态与排查" aria-label="Permalink to &quot;状态与排查&quot;">​</a></h2><h3 id="status" tabindex="-1"><code>/status</code> <a class="header-anchor" href="#status" aria-label="Permalink to &quot;`/status`&quot;">​</a></h3><p>当前会话级：消息数、上下文占用、缓存命中、读写 token、本路用过的技能等。</p><table tabindex="0"><thead><tr><th>动作</th><th>用法</th></tr></thead><tbody><tr><td><code>show</code></td><td><code>/status</code> 或 <code>/status show</code>，当前路由</td></tr><tr><td><code>latest</code></td><td>若当前路由没有活跃会话，要看<strong>该机器人最新</strong>会话时用</td></tr></tbody></table><h3 id="access" tabindex="-1"><code>/access</code> <a class="header-anchor" href="#access" aria-label="Permalink to &quot;`/access`&quot;">​</a></h3><p>看当前渠道身份、绑定的用户、角色、写命令是否允许、渠道/会话/thread 范围、ACL 结果。排绑定、ACL、为何拒绝写命令时用。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/access</span></span></code></pre></div><h3 id="usage" tabindex="-1"><code>/usage</code> <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;`/usage`&quot;">​</a></h3><p>最近 7 天 token。</p><table tabindex="0"><thead><tr><th>动作</th><th>用法</th></tr></thead><tbody><tr><td><code>summary</code></td><td><code>/usage</code> 或 <code>/usage summary</code></td></tr><tr><td><code>by-model</code></td><td><code>/usage by-model</code></td></tr></tbody></table><h3 id="heartbeat" tabindex="-1"><code>/heartbeat</code> <a class="header-anchor" href="#heartbeat" aria-label="Permalink to &quot;`/heartbeat`&quot;">​</a></h3><p>最近心跳执行记录。</p><table tabindex="0"><thead><tr><th>动作</th><th>用法</th></tr></thead><tbody><tr><td><code>logs</code></td><td><code>/heartbeat</code> 或 <code>/heartbeat logs</code></td></tr></tbody></table><h3 id="email" tabindex="-1"><code>/email</code> <a class="header-anchor" href="#email" aria-label="Permalink to &quot;`/email`&quot;">​</a></h3><p>当前机器人邮服、绑定、发件箱。</p><table tabindex="0"><thead><tr><th>动作</th><th>用法</th></tr></thead><tbody><tr><td><code>providers</code></td><td><code>/email providers</code></td></tr><tr><td><code>bindings</code></td><td><code>/email bindings</code></td></tr><tr><td><code>outbox</code></td><td><code>/email outbox</code></td></tr></tbody></table><hr><h2 id="配置类" tabindex="-1">配置类 <a class="header-anchor" href="#配置类" aria-label="Permalink to &quot;配置类&quot;">​</a></h2><h3 id="settings" tabindex="-1"><code>/settings</code> <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;`/settings`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>动作</th><th>用法</th><th>权限</th></tr></thead><tbody><tr><td><code>get</code></td><td><code>/settings</code> 或 <code>/settings get</code></td><td>全体</td></tr><tr><td><code>update</code></td><td><code>/settings update [options]</code></td><td>Owner</td></tr></tbody></table><p><code>update</code> 常见选项：</p><table tabindex="0"><thead><tr><th>选项</th><th>说明</th></tr></thead><tbody><tr><td><code>--language</code></td><td>如 <code>en</code>、<code>zh</code></td></tr><tr><td><code>--acl_default_effect</code></td><td><code>allow</code> / <code>deny</code></td></tr><tr><td><code>--reasoning_enabled</code></td><td><code>true</code> / <code>false</code></td></tr><tr><td><code>--reasoning_effort</code></td><td><code>low</code> / <code>medium</code> / <code>high</code></td></tr><tr><td><code>--heartbeat_enabled</code></td><td><code>true</code> / <code>false</code></td></tr><tr><td><code>--heartbeat_interval</code></td><td>分钟</td></tr><tr><td><code>--chat_model_id</code></td><td>聊天模型 UUID</td></tr><tr><td><code>--heartbeat_model_id</code></td><td>心跳模型 UUID</td></tr></tbody></table><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/settings update --language en --heartbeat_enabled true --heartbeat_interval 30</span></span></code></pre></div><h3 id="model" tabindex="-1"><code>/model</code> <a class="header-anchor" href="#model" aria-label="Permalink to &quot;`/model`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>动作</th><th>用法</th><th>权限</th></tr></thead><tbody><tr><td><code>list [provider_name]</code></td><td><code>/model list</code></td><td>全体</td></tr><tr><td><code>current</code></td><td><code>/model current</code></td><td>全体</td></tr><tr><td><code>set</code></td><td><code>/model set &lt;model_id&gt;</code> 或 <code>/model set &lt;provider_name&gt; &lt;model_name&gt;</code></td><td>Owner</td></tr><tr><td><code>set-heartbeat</code></td><td>同理，心跳模型</td><td>Owner</td></tr></tbody></table><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/model list</span></span>\n<span class="line"><span>/model list OpenAI</span></span>\n<span class="line"><span>/model current</span></span>\n<span class="line"><span>/model set gpt-4o</span></span>\n<span class="line"><span>/model set OpenAI gpt-4o</span></span></code></pre></div><h3 id="memory" tabindex="-1"><code>/memory</code> <a class="header-anchor" href="#memory" aria-label="Permalink to &quot;`/memory`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>动作</th><th>用法</th><th>权限</th></tr></thead><tbody><tr><td><code>list</code></td><td><code>/memory list</code></td><td>全体</td></tr><tr><td><code>current</code></td><td><code>/memory current</code></td><td>全体</td></tr><tr><td><code>set</code></td><td><code>/memory set &lt;name&gt;</code></td><td>Owner</td></tr></tbody></table><h3 id="search" tabindex="-1"><code>/search</code> <a class="header-anchor" href="#search" aria-label="Permalink to &quot;`/search`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>动作</th><th>用法</th><th>权限</th></tr></thead><tbody><tr><td><code>list</code></td><td><code>/search list</code></td><td>全体</td></tr><tr><td><code>current</code></td><td><code>/search current</code></td><td>全体</td></tr><tr><td><code>set</code></td><td><code>/search set &lt;name&gt;</code></td><td>Owner</td></tr></tbody></table><h3 id="mcp" tabindex="-1"><code>/mcp</code> <a class="header-anchor" href="#mcp" aria-label="Permalink to &quot;`/mcp`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>动作</th><th>用法</th><th>权限</th></tr></thead><tbody><tr><td><code>list</code></td><td><code>/mcp list</code></td><td>全体</td></tr><tr><td><code>get</code></td><td><code>/mcp get &lt;name&gt;</code></td><td>全体</td></tr><tr><td><code>delete</code></td><td><code>/mcp delete &lt;name&gt;</code></td><td>Owner</td></tr></tbody></table><hr><h2 id="自动化与文件" tabindex="-1">自动化与文件 <a class="header-anchor" href="#自动化与文件" aria-label="Permalink to &quot;自动化与文件&quot;">​</a></h2><h3 id="schedule" tabindex="-1"><code>/schedule</code> <a class="header-anchor" href="#schedule" aria-label="Permalink to &quot;`/schedule`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>动作</th><th>用法</th><th>权限</th></tr></thead><tbody><tr><td><code>list</code></td><td><code>/schedule list</code></td><td>全体</td></tr><tr><td><code>get</code></td><td><code>/schedule get &lt;name&gt;</code></td><td>全体</td></tr><tr><td><code>create</code></td><td><code>/schedule create &lt;name&gt; &lt;pattern&gt; &lt;command&gt;</code></td><td>Owner</td></tr><tr><td><code>update</code></td><td><code>/schedule update &lt;name&gt; [--pattern P] [--command C]</code></td><td>Owner</td></tr><tr><td><code>delete</code></td><td><code>/schedule delete &lt;name&gt;</code></td><td>Owner</td></tr><tr><td><code>enable</code></td><td><code>/schedule enable &lt;name&gt;</code></td><td>Owner</td></tr><tr><td><code>disable</code></td><td><code>/schedule disable &lt;name&gt;</code></td><td>Owner</td></tr></tbody></table><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/schedule list</span></span>\n<span class="line"><span>/schedule create morning-news &quot;0 9 * * *&quot; &quot;Summarize today&#39;s top tech news&quot;</span></span>\n<span class="line"><span>/schedule disable morning-news</span></span></code></pre></div><h3 id="skill" tabindex="-1"><code>/skill</code> <a class="header-anchor" href="#skill" aria-label="Permalink to &quot;`/skill`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>动作</th><th>用法</th></tr></thead><tbody><tr><td><code>list</code></td><td><code>/skill</code> 或 <code>/skill list</code></td></tr></tbody></table><h3 id="fs" tabindex="-1"><code>/fs</code> <a class="header-anchor" href="#fs" aria-label="Permalink to &quot;`/fs`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>动作</th><th>用法</th></tr></thead><tbody><tr><td><code>list</code></td><td><code>/fs list [path]</code></td></tr><tr><td><code>read</code></td><td><code>/fs read &lt;path&gt;</code></td></tr></tbody></table><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/fs list /</span></span>\n<span class="line"><span>/fs list /home</span></span>\n<span class="line"><span>/fs read /home/bot/IDENTITY.md</span></span></code></pre></div><p>文件太大时输出会截断。</p><hr><h2 id="compact" tabindex="-1"><code>/compact</code> <a class="header-anchor" href="#compact" aria-label="Permalink to &quot;`/compact`&quot;">​</a></h2><p>立刻对<strong>当前会话</strong>做 <a href="/zh/getting-started/compaction.html">会话上下文压缩</a>，<strong>不是</strong>改记忆库里条目的那种记忆压缩。</p><table tabindex="0"><thead><tr><th>动作</th><th>用法</th></tr></thead><tbody><tr><td><code>run</code></td><td><code>/compact</code> 或 <code>/compact run</code></td></tr></tbody></table><p>聊得很长、想先摘要再续时有用。</p>',91)])])}const u=e(c,[["render",s]]);export{b as __pageData,u as default};
